import{_ as t,o as r,c as a,a2 as o}from"./chunks/framework.BWuWLRhz.js";const n="/images/life-weeks/Years.png",s="/images/life-weeks/Months1.png",i="/images/life-weeks/Weeks.png",l="/images/life-weeks/Weeks-block-LIFE1.png",p="/images/life-weeks/Weeks-block-DEATHS2.png",f="/images/life-weeks/Weeks-block-WOODS1.png",h="/images/life-weeks/Weeks-block-template-EINSTEIN-3.png",c="/images/life-weeks/Weeks-block-YOU.png",m="/images/life-weeks/Diamond-ring2.png",w="/images/life-weeks/spoon-of-diamonds1.png",g="/images/life-weeks/Venn1.png",u="/images/life-weeks/Calendar-Button-HuffPost-1024x794.png",b="/images/life-weeks/pinit_fg_en_rect_gray_20.png",T=JSON.parse('{"title":"Your Life in Weeks","description":"","frontmatter":{"title":"Your Life in Weeks","titleZh":"以你的一生(以周为单位)","date":"2014-05-07T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/05/life-weeks.html","slug":"life-weeks"},"headers":[],"relativePath":"posts/life-weeks.md","filePath":"posts/life-weeks.md","lastUpdated":1782886257000}'),k={name:"posts/life-weeks.md"};function _(d,e,y,W,P,x){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="以你的一生-以周为单位-·-your-life-in-weeks" tabindex="-1">以你的一生(以周为单位) · Your Life in Weeks <a class="header-anchor" href="#以你的一生-以周为单位-·-your-life-in-weeks" aria-label="Permalink to &quot;以你的一生(以周为单位) · Your Life in Weeks&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/05/life-weeks.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/05/life-weeks.html</a> · 2014-05-07</p></blockquote><p><em><strong>注:</strong> 如果你想把这篇文章打印出来或离线阅读,PDF 版本可能是更好的选择。你可以<a href="https://gum.co/life-weeks" target="_blank" rel="noreferrer">在这里购买</a>。</em></p><p>以年为单位来看,一段漫长的人生是这样的:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/05/Years.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="A Human Life in Years"></a></p><p>以月为单位来看,人生是这样的:</p><p><a href="http://store.waitbutwhy.com/collections/life-calendars" target="_blank" rel="noreferrer"><img src="'+s+'" alt="A Human Life in Months"></a></p><p>但今天,我们要以周为单位来看人生:</p><p><a href="http://store.waitbutwhy.com/collections/life-calendars" target="_blank" rel="noreferrer"><img src="'+i+'" alt="A Human Life in Weeks"></a></p><p>每一行周数构成一年。把一个新生儿变成 90 岁老人,需要的就是这么多周。</p><p>我们总感觉自己的人生是由数不清的周组成的。但它们就在这儿——完全可数——直勾勾地盯着你。</p><p>在进一步讨论之前,我们先来看看一个典型的美国人是怎么度过这些周的:</p><p><a href="http://store.waitbutwhy.com/collections/life-calendars" target="_blank" rel="noreferrer"><img src="'+l+'" alt="American Life in Weeks"></a><br> 来源: <a href="#footnote-1-1470">1</a><a href="#footnote-2-1470">2</a><a href="#footnote-3-1470">3</a><a href="#footnote-4-1470">4</a><a href="#footnote-5-1470">5</a></p><p>这张周数图还有一些其他有趣的用法:</p><p><a href="http://store.waitbutwhy.com/collections/life-calendars" target="_blank" rel="noreferrer"><img src="'+p+'" alt="Famous Deaths in Weeks"></a></p><p><a href="http://store.waitbutwhy.com/collections/life-calendars" target="_blank" rel="noreferrer"><img src="'+f+'" alt="Woods and Federer in Weeks"></a></p><p><a href="http://store.waitbutwhy.com/collections/life-calendars" target="_blank" rel="noreferrer"><img src="'+h+'" alt="Einstein and Newton in Weeks"></a></p><p>那么<a href="http://store.waitbutwhy.com/collections/life-calendars" target="_blank" rel="noreferrer">你的周数</a>呢?</p><p><a href="http://store.waitbutwhy.com/collections/life-calendars" target="_blank" rel="noreferrer"><img src="'+c+'" alt="You in Weeks"></a></p><p>有时候生命似乎很短暂,有时候又长得不可思议。但这张图强调的是:生命是绝对有限的。这些就是你的周,这就是你所拥有的一切。</p><p>鉴于这个事实,能用来形容你的周数的唯一合适的词就是<em>珍贵</em>。永恒中有数万亿个万亿个周,而这一小把是你的。顺着「珍贵」这个主题,我们不妨把你的每一周想象成一颗小宝石,比如一颗 2 毫米、0.05 克拉的钻石。就像这颗:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/05/Diamond-ring2.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt=".05 Carat Diamond"></a></p><p>把一颗 0.05 克拉钻石的体积乘以 90 年里的周数(4680),加起来还不到一汤匙。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/05/spoon-of-diamonds1.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt="Spoonful of Diamonds"></a></p><p>看着这一勺钻石,有一个非常明确的问题需要问:「你有在最大化利用你的这些周吗?」</p><p>在思考我自己的每一周以及我通常如何使用它们时,我认为有两种使用钻石的好方法:</p><ol><li><p>享受这颗钻石</p></li><li><p>用它来建造某种东西,让你未来的钻石或别人的钻石变得更值得享受</p></li></ol><p>换句话说,你有这么一小勺钻石,你真的很想创造一种生活,让它们能让你<em>快乐</em>。如果一颗钻石没有让你快乐,那唯一的理由应该是——你在用它让别的钻石(无论是你自己未来的,还是别人的)吞下去更顺口。理想状态下,你在 #1 和 #2 之间平衡得很好,而且经常能同时完成两件事(比如你热爱自己工作的那些时刻)。</p><p>当然,如果一颗钻石很享受,但你享受它的同时正在坑害你未来的钻石(这是<a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">即时满足猴子 (Instant Gratification Monkey)</a> 的拿手好戏),那就不太妙了。同样,如果你一颗接一颗地用钻石去为未来建造某个东西,但这个过程并不让你快乐,而且看起来遥遥无期没有尽头,那也不算好事。</p><p>但使用钻石最糟糕的方式,是既没做到 #1 也没做到 #2。有时候「两头不占」发生在你选错了职业或选错了伴侣的时候,它往往是勇气、自律或创造力不足的症状。有时候「两头不占」是因为某个让人无力的问题。</p><p>我们都经历过「两头不占的一周」,那种感觉很糟糕。当一长串这样的星期连续发生时,你会变得抑郁、沮丧、绝望,以及一堆其他让人心烦的形容词。「两头不占的一周」不可避免,有时甚至很重要——一个特别糟糕的「两头不占的一周」经常会引出改变人生的顿悟——但尽量减少这类星期的数量,是一个值得追求的目标。</p><p>一切可以这样总结:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/05/Venn1.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="The Contents of Your Week"></a></p><p><strong>人生日历 (The Life Calendar)</strong></p><p>我们最终陷入「两头不占之地」的方式之一,就是没有对事情思考得足够深——所以最关键的技能之一,就是持续的反思和自我觉察。否则,你会不知不觉地陷入某种惯性沟槽,浪费掉一大堆宝贵的钻石。</p><p>为了帮助你(也帮助我们自己)保持清醒、避开「两头不占之地」,我们做了一个人生日历 (Life Calendar),把你人生中的每一个星期都摊在一张纸上。我们通常不在文章里推销产品,但这一次,它们是天生一对。</p><p>这张日历是 24 英寸 × 36 英寸的海报,印在高质量海报纸上,可以在上面写字,能保存几十年。售价 20 美元,你可以在<a href="http://store.waitbutwhy.com/collections/posters/products/life-calendar-24x36" target="_blank" rel="noreferrer">这里</a>购买。</p><p>除了鼓励定期反思之外,我们希望这份日历能帮你在人生中找到方向感,帮你设定目标并督促自己达成,并提醒你为自己已经取得的成就感到骄傲、为勺子里的钻石心怀感激。</p><p>至于怎么用这份日历,完全可以发挥创意。以下是一些可能的玩法:</p><ul><li>把过去的每一周用不同颜色标出来,划分成不同的「人生章节」——比如高中、大学、第一份工作、第二份工作、搬到新城市、订婚、结婚等等,或者用你自己对「人生章节」的理解来划分。你也可以在关键转折点发生的那些格子上做特殊标记。</li><li>每过一周,就在那个格子里写点什么——格子够大,用削尖的铅笔可以写下几个字。</li><li>把未来的目标标在某个未来的格子上,直观地看到自己还有多少周可以去实现它。</li><li>如果你刚当上父母,给孩子做一份可能会很有意思,这样他们以后可以回头看看自己人生最初几年发生过什么事。</li><li>或者,你也可以选择完全不动它。</li></ul><p>无论是上面那张周格图还是这份人生日历,对我来说都是一种提醒:眼前这一格格空白的方框是<strong>我的</strong>。我们常常觉得自己被困在某种既定的生活里,但这一整张空白格子可以变成我们想要的任何模样。你认识的每一个人、你钦佩的每一个人、历史上的每一位英雄——他们都是用同样一张空白格子做到了这一切。</p><p>这些格子也提醒我:生活是宽容的。不管这一周发生了什么,下一周你都会拿到一个崭新的格子重新开始。这让我很想干脆放弃新年计划——反正它们从来也没管用过——转而在每个周日晚上做一份新的<strong>每周计划</strong>。每一个空白格子都是一次把这一周过好的机会——这一点值得记住。</p><p><strong>日历购买链接:</strong><a href="http://store.waitbutwhy.com/collections/posters/products/life-calendar-12x18-hand-screen-printed" target="_blank" rel="noreferrer"><br></a></p><h2 id="" tabindex="-1"><a href="http://store.waitbutwhy.com/collections/life-calendars" target="_blank" rel="noreferrer"><img src="'+u+'" alt="Calendar Button (HuffPost)"></a> <a class="header-anchor" href="#" aria-label="Permalink to &quot;[![Calendar Button (HuffPost)](/images/life-weeks/Calendar-Button-HuffPost-1024x794.png)](http://store.waitbutwhy.com/collections/life-calendars)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会发给你。</p><h2 id="想支持-wait-but-why-请访问我们的-patreon-页面。" tabindex="-1">想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。 <a class="header-anchor" href="#想支持-wait-but-why-请访问我们的-patreon-页面。" aria-label="Permalink to &quot;想支持 Wait But Why,请访问我们的 **[Patreon 页面](https://patreon.com/waitbutwhy)**。&quot;">​</a></h2><p><em>想打印或离线阅读这篇文章,可以<a href="https://gum.co/life-weeks" target="_blank" rel="noreferrer">购买 PDF 版本</a>。</em></p><p><strong>更多帮你重新审视人生的文章:</strong></p><p><a href="https://waitbutwhy.com/2013/11/life-is-picture-but-you-live-in-pixel.html" target="_blank" rel="noreferrer">人生是一幅画,但你活在一个像素里 (Life is a Picture, But You Live in a Pixel)</a></p><p><a href="https://waitbutwhy.com/2013/08/putting-time-in-perspective.html" target="_blank" rel="noreferrer">把时间放进视角里 (Putting Time in Perspective)</a></p><p><a href="https://waitbutwhy.com/2014/01/your-family-past-present-and-future.html" target="_blank" rel="noreferrer">你的家族:过去、现在、未来 (Your Family: Past, Present, and Future)</a></p><p><a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer">驯服猛犸象:为什么你不该在意别人怎么看你</a></p><hr><ol><li><p><a href="http://www.gallup.com/poll/168707/average-retirement-age-rises.aspx" target="_blank" rel="noreferrer">http://www.gallup.com/poll/168707/average-retirement-age-rises.aspx</a><a href="#note-1-1470">↩</a></p></li><li><p><a href="http://www.babycenter.com/0_surprising-facts-about-birth-in-the-united-states_1372273.bc" target="_blank" rel="noreferrer">http://www.babycenter.com/0_surprising-facts-about-birth-in-the-united-states_1372273.bc</a><a href="#note-2-1470">↩</a></p></li><li><p><a href="http://www.pewsocialtrends.org/2011/12/14/barely-half-of-u-s-adults-are-married-a-record-low/" target="_blank" rel="noreferrer">http://www.pewsocialtrends.org/2011/12/14/barely-half-of-u-s-adults-are-married-a-record-low/</a><a href="#note-3-1470">↩</a></p></li><li><p><a href="http://www.census.gov/prod/2011pubs/p70-125.pdf" target="_blank" rel="noreferrer">http://www.census.gov/prod/2011pubs/p70-125.pdf</a><a href="#note-4-1470">↩</a></p></li><li><p><a href="http://www.forbes.com/sites/jeannemeister/2012/08/14/job-hopping-is-the-new-normal-for-millennials-three-ways-to-prevent-a-human-resource-nightmare/" target="_blank" rel="noreferrer">http://www.forbes.com/sites/jeannemeister/2012/08/14/job-hopping-is-the-new-normal-for-millennials-three-ways-to-prevent-a-human-resource-nightmare/</a><a href="#note-5-1470">↩</a></p></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/05/life-weeks.html&amp;description=Your%20Life%20in%20Weeks" target="_blank" rel="noreferrer"><img src="'+b+'" alt=""></a></p>',56)])])}const Y=t(k,[["render",_]]);export{T as __pageData,Y as default};
